+        return switch (@typeInfo(T)) {
+            .int, .comptime_int => .{ .real = @floatFromInt(value), .imag = 0.0 },
+            .float, .comptime_float => .{ .real = value, .imag = 0.0 },
+            .bool => .{ .real = if (value) 1.0 else 0.0, .imag = 0.0 },
+            else => .{ .real = 0.0, .imag = 0.0 },
+        };
